"use strict";
Array.from(document.getElementsByClassName("menu is-menu-main")).forEach(
    function (e) {
        Array.from(e.getElementsByClassName("has-dropdown-icon")).forEach(
            function (e) {
                e.addEventListener("click", function (e) {
                    var t = e.currentTarget
                        .getElementsByClassName("dropdown-icon")[0]
                        .getElementsByClassName("mdi")[0];
                    e.currentTarget.parentNode.classList.toggle("is-active"),
                        t.classList.toggle("mdi-plus"),
                        t.classList.toggle("mdi-minus");
                });
            }
        );
    }
),
    Array.from(
        document.getElementsByClassName("jb-aside-mobile-toggle")
    ).forEach(function (e) {
        e.addEventListener("click", function (e) {
            e = e.currentTarget
                .getElementsByClassName("icon")[0]
                .getElementsByClassName("mdi")[0];
            document.documentElement.classList.toggle(
                "has-aside-mobile-expanded"
            ),
                e.classList.toggle("mdi-forwardburger"),
                e.classList.toggle("mdi-backburger");
        });
    }),
    Array.from(
        document.getElementsByClassName("jb-navbar-menu-toggle")
    ).forEach(function (e) {
        e.addEventListener("click", function (e) {
            var t = e.currentTarget
                .getElementsByClassName("icon")[0]
                .getElementsByClassName("mdi")[0];
            document
                .getElementById(e.currentTarget.getAttribute("data-target"))
                .classList.toggle("is-active"),
                t.classList.toggle("mdi-dots-vertical"),
                t.classList.toggle("mdi-close");
        });
    }),
    Array.from(document.getElementsByClassName("jb-modal")).forEach(function (
        e
    ) {
        e.addEventListener("click", function (e) {
            e = e.currentTarget.getAttribute("data-target");
            document.getElementById(e).classList.add("is-active"),
                document.documentElement.classList.add("is-clipped");
        });
    }),
    Array.from(document.getElementsByClassName("jb-modal-close")).forEach(
        function (e) {
            e.addEventListener("click", function (e) {
                e.currentTarget.closest(".modal").classList.remove("is-active"),
                    document.documentElement.classList.remove("is-clipped");
            });
        }
    ),
    Array.from(
        document.getElementsByClassName("jb-notification-dismiss")
    ).forEach(function (e) {
        e.addEventListener("click", function (e) {
            e.currentTarget.closest(".notification").classList.add("is-hidden");
        });
    });

document.addEventListener("DOMContentLoaded", () => {
    (document.querySelectorAll(".notification .delete") || []).forEach(
        ($delete) => {
            const $notification = $delete.parentNode;

            $delete.addEventListener("click", () => {
                $notification.parentNode.removeChild($notification);
            });
        }
    );
});

document.addEventListener("DOMContentLoaded", function () {
    const toggles = document.querySelectorAll(".toggle-menu");

    toggles.forEach((toggle) => {
        toggle.addEventListener("click", function (e) {
            e.preventDefault();

            const submenu = this.nextElementSibling;
            const arrow = this.querySelector(".arrow i");

            if (!submenu) return;

            const isOpen = submenu.style.display === "block";

            // Fermer tous les autres sous-menus
            document.querySelectorAll(".submenu").forEach((menu) => {
                menu.style.display = "none";
            });

            document
                .querySelectorAll(".toggle-menu .arrow i")
                .forEach((icon) => {
                    icon.style.transform = "rotate(0deg)";
                });

            // Ouvrir / fermer le menu courant
            if (!isOpen) {
                submenu.style.display = "block";
                if (arrow) {
                    arrow.style.transform = "rotate(180deg)";
                    arrow.style.transition = "transform 0.3s";
                }
            }
        });
    });
});
